def slugify(s):
    return re.sub(r'[^a-z0-9]+','-',s.lower()).strip('-')

def architecture_svg(item):
    title, slug, cat, tagline, scale, comps, focuses, followups = item
    colors = ["#111827", "#164e63", "#14532d", "#4c1d95", "#7c2d12", "#831843"]
    strokes = ["#94a3b8", "#22d3ee", "#4ade80", "#c4b5fd", "#fb923c", "#f472b6"]
    x = [35, 205, 375, 545, 715, 885]
    arrows = ''.join(f'<path d="M{x[i]+130} 129 H{x[i+1]-12}" class="arrow" marker-end="url(#arrow)"/>' for i in range(5))
    boxes = ''
    for i, name in enumerate(comps):
        sub = ["entry & protocol","stateless compute","coordination / policy","durable state","async processing","query & operations"][i]
        boxes += f'<g><rect x="{x[i]}" y="84" width="130" height="88" rx="10" fill="{colors[i]}" stroke="{strokes[i]}"/><text x="{x[i]+65}" y="117" text-anchor="middle" class="node">{escape(name)}</text><text x="{x[i]+65}" y="139" text-anchor="middle" class="node-sub">{sub}</text><circle cx="{x[i]+65}" cy="164" r="10" fill="{strokes[i]}"/><text x="{x[i]+65}" y="168" text-anchor="middle" class="step">{i+1}</text></g>'
    branch = f'<path d="M610 172 V230 H780" class="async" marker-end="url(#arrow2)"/><rect x="780" y="205" width="190" height="62" rx="10" fill="#172033" stroke="#fb923c"/><text x="875" y="232" text-anchor="middle" class="node">Async side effects</text><text x="875" y="251" text-anchor="middle" class="node-sub">events · audit · analytics</text>'
    return f'''<svg viewBox="0 0 1050 310" role="img" aria-label="{escape(title)} high-level architecture"><defs><marker id="arrow" markerWidth="9" markerHeight="7" refX="8" refY="3.5" orient="auto"><polygon points="0 0,9 3.5,0 7" fill="#64748b"/></marker><marker id="arrow2" markerWidth="9" markerHeight="7" refX="8" refY="3.5" orient="auto"><polygon points="0 0,9 3.5,0 7" fill="#fb923c"/></marker><pattern id="grid" width="28" height="28" patternUnits="userSpaceOnUse"><path d="M28 0H0V28" fill="none" stroke="#1e293b" stroke-width=".5"/></pattern></defs><rect width="1050" height="310" fill="#07101f"/><rect width="1050" height="310" fill="url(#grid)"/><text x="35" y="35" class="diagram-title">{escape(title.upper())} · REQUEST + DATA FLOW</text><text x="35" y="55" class="diagram-note">Solid = synchronous path · dashed orange = asynchronous side effects</text>{arrows}{branch}{boxes}</svg>'''

def sequence_svg(item):
    title, slug, cat, tagline, scale, comps, focuses, followups = item
    cols=[95,305,515,725,935]
    names=[comps[0],comps[1],comps[2],comps[3],comps[-1]]
    heads=''.join(f'<rect x="{x-65}" y="38" width="130" height="42" rx="8" class="seq-head"/><text x="{x}" y="63" text-anchor="middle" class="node">{escape(n)}</text><line x1="{x}" y1="80" x2="{x}" y2="310" class="life"/>' for x,n in zip(cols,names))
    labels=["submit / request","validate + route","read or reserve","persist atomically","acknowledge / emit"]
    lines=''
    for i in range(4):
        y=115+i*48
        lines+=f'<path d="M{cols[i]} {y} H{cols[i+1]-8}" class="seq-arrow" marker-end="url(#sa)"/><text x="{(cols[i]+cols[i+1])/2}" y="{y-8}" text-anchor="middle" class="diagram-note">{labels[i]}</text>'
    lines+=f'<path d="M{cols[4]} 285 H{cols[0]+8}" class="seq-return" marker-end="url(#sa)"/><text x="515" y="277" text-anchor="middle" class="diagram-note">{labels[4]}</text>'
    return f'''<svg viewBox="0 0 1030 340" role="img" aria-label="{escape(title)} critical sequence"><defs><marker id="sa" markerWidth="9" markerHeight="7" refX="8" refY="3.5" orient="auto"><polygon points="0 0,9 3.5,0 7" fill="#94a3b8"/></marker><pattern id="gseq" width="28" height="28" patternUnits="userSpaceOnUse"><path d="M28 0H0V28" fill="none" stroke="#1e293b" stroke-width=".5"/></pattern></defs><rect width="1030" height="340" fill="#07101f"/><rect width="1030" height="340" fill="url(#gseq)"/><text x="28" y="24" class="diagram-title">CRITICAL FLOW</text>{heads}{lines}</svg>'''

